    QUERIES NUMBER(12,0),
    FAILS NUMBER(12,0),
    QUEUED_MIN NUMBER(18,2),
    SPILL_GB NUMBER(18,3),
    P95_S NUMBER(18,1),
    EXEC_HOURS NUMBER(18,3),
    BILLED_HOURS NUMBER(12,0),
    ACTIVE_HOURS NUMBER(12,0),
    IDLE_PCT NUMBER(6,2),
    CREDITS_PER_QUERY NUMBER(18,6),
    LOAD_TS TIMESTAMP_NTZ NOT NULL DEFAULT CURRENT_TIMESTAMP()
