-- First pass now so existing registry rows get their who.
CALL DBA_MAINT_DB.OVERWATCH.SP_CHANGE_ATTRIBUTION();

MERGE INTO DBA_MAINT_DB.OVERWATCH.SCHEMA_VERSION t
