--
-- Derivation law: SP_LOAD_DAILY_FACTS from V041; SP_LOAD_MARTS_V27,
-- SP_REFRESH_EXEC_BOARD, SP_LOAD_PLATFORM_SCORE, SP_PURGE_FACTS,
-- SP_NIGHTLY_RECONCILE from V042; SP_ALERT_SCAN from V023; the freshness
