-- ===========================================================================
-- >>> V046__storage_truth.sql
-- ===========================================================================
-- V046: storage truth (COST_DB reconciliation R3 + audit F1b, 2026-07-14).
-- Per-database storage (FACT_STORAGE_DAILY) covers table + fail-safe only and
-- the app now prices it on the monthly average of daily bytes (F1, app-side).
-- This migration adds the ACCOUNT-LEVEL tiers Snowflake bills but we ignored:
-- stage, hybrid-table, and archive cool/cold storage, sourced from
-- ACCOUNT_USAGE.STORAGE_USAGE (one row per day, account-wide — no per-database
-- grain exists for these tiers). A new fact + loader proc + daily task keep it
-- fresh; tier rates seed into SETTINGS (Admin-editable estimates).
--
-- NOTE: STORAGE_USAGE is Snowflake's own approximation and "won't match your
-- invoice exactly" (docs) — org USAGE_IN_CURRENCY remains billing truth. This
-- fact is a NEW proc/task, not a re-derivation of the byte-locked loaders.
-- Apply AFTER V045. Idempotent; safe to re-run.

EXECUTE IMMEDIATE
$$
DECLARE
    v NUMBER;
    not_ready EXCEPTION (-20046, 'V046 requires V045 first - apply migrations in order.');
BEGIN
    SELECT MAX(VERSION) INTO :v FROM DBA_MAINT_DB.OVERWATCH.SCHEMA_VERSION;
    IF (v < 45) THEN
        RAISE not_ready;
    END IF;
END;
$$;

-- Account-level storage by tier (average daily bytes, billing basis).
CREATE TRANSIENT TABLE IF NOT EXISTS DBA_MAINT_DB.OVERWATCH.FACT_STORAGE_ACCOUNT_DAILY (
    DAY                DATE          NOT NULL,
    TABLE_BYTES        NUMBER(24,0),
    STAGE_BYTES        NUMBER(24,0),
    FAILSAFE_BYTES     NUMBER(24,0),
    HYBRID_BYTES       NUMBER(24,0),
    ARCHIVE_COOL_BYTES NUMBER(24,0),
    ARCHIVE_COLD_BYTES NUMBER(24,0),
    LOAD_TS            TIMESTAMP_NTZ NOT NULL DEFAULT CURRENT_TIMESTAMP()
);

CREATE OR REPLACE PROCEDURE DBA_MAINT_DB.OVERWATCH.SP_LOAD_STORAGE_TRUTH(DAYS_BACK FLOAT)
RETURNS VARCHAR
LANGUAGE SQL
EXECUTE AS OWNER
AS
$$
DECLARE
    lo DATE;
BEGIN
    lo := DATEADD('day', -GREATEST(COALESCE(:DAYS_BACK, 3), 1)::INT, CURRENT_DATE());
    DELETE FROM DBA_MAINT_DB.OVERWATCH.FACT_STORAGE_ACCOUNT_DAILY WHERE DAY >= :lo;
    INSERT INTO DBA_MAINT_DB.OVERWATCH.FACT_STORAGE_ACCOUNT_DAILY
        (DAY, TABLE_BYTES, STAGE_BYTES, FAILSAFE_BYTES, HYBRID_BYTES, ARCHIVE_COOL_BYTES, ARCHIVE_COLD_BYTES)
    SELECT
        USAGE_DATE,
        SUM(COALESCE(STORAGE_BYTES, 0)),
        SUM(COALESCE(STAGE_BYTES, 0)),
        SUM(COALESCE(FAILSAFE_BYTES, 0)),
        SUM(COALESCE(HYBRID_TABLE_STORAGE_BYTES, 0)),
        SUM(COALESCE(ARCHIVE_STORAGE_COOL_BYTES, 0)),
        SUM(COALESCE(ARCHIVE_STORAGE_COLD_BYTES, 0))
    FROM SNOWFLAKE.ACCOUNT_USAGE.STORAGE_USAGE
    WHERE USAGE_DATE >= :lo
    GROUP BY USAGE_DATE;

    MERGE INTO DBA_MAINT_DB.OVERWATCH.SOURCE_FRESHNESS_STATE t
    USING (
        SELECT 'FACT_STORAGE_ACCOUNT_DAILY' AS SOURCE_NAME,
               MAX(LOAD_TS) AS LAST_LOAD_TS, COUNT(*) AS ROW_COUNT
        FROM DBA_MAINT_DB.OVERWATCH.FACT_STORAGE_ACCOUNT_DAILY
    ) s
    ON t.SOURCE_NAME = s.SOURCE_NAME
    WHEN MATCHED THEN UPDATE SET
        t.LAST_LOAD_TS = s.LAST_LOAD_TS, t.ROW_COUNT = s.ROW_COUNT,
        t.SNAPSHOT_TS = CURRENT_TIMESTAMP()
    WHEN NOT MATCHED THEN INSERT (SOURCE_NAME, LAST_LOAD_TS, ROW_COUNT)
    VALUES (s.SOURCE_NAME, s.LAST_LOAD_TS, s.ROW_COUNT);

    RETURN 'OK';
END;
$$;

-- Tier rates: seed only if absent (never clobber an Admin edit). Estimates
-- from AWS US-East list pricing; hybrid/archive bill differently from standard.
MERGE INTO DBA_MAINT_DB.OVERWATCH.SETTINGS t
USING (
    SELECT * FROM VALUES
        ('STORAGE_STAGE_USD_PER_TB_MONTH',        '23.00'),
        ('STORAGE_HYBRID_USD_PER_TB_MONTH',       '348.16'),
        ('STORAGE_ARCHIVE_COOL_USD_PER_TB_MONTH', '4.00'),
        ('STORAGE_ARCHIVE_COLD_USD_PER_TB_MONTH', '1.00')
    AS s(KEY, VALUE)
) s
ON t.KEY = s.KEY
WHEN NOT MATCHED THEN INSERT (KEY, VALUE) VALUES (s.KEY, s.VALUE);

-- First fill (90d) so the panel has history immediately.
CALL DBA_MAINT_DB.OVERWATCH.SP_LOAD_STORAGE_TRUTH(90);

CREATE TASK IF NOT EXISTS DBA_MAINT_DB.OVERWATCH.TASK_LOAD_STORAGE_TRUTH
    WAREHOUSE = WH_ALFA_OVERWATCH
    SCHEDULE = 'USING CRON 30 6 * * * America/Chicago'
AS
    CALL DBA_MAINT_DB.OVERWATCH.SP_LOAD_STORAGE_TRUTH(3);

ALTER TASK IF EXISTS DBA_MAINT_DB.OVERWATCH.TASK_LOAD_STORAGE_TRUTH RESUME;

INSERT INTO DBA_MAINT_DB.OVERWATCH.SCHEMA_VERSION (VERSION, DESCRIPTION)
SELECT 46 AS VERSION,
       'storage truth: FACT_STORAGE_ACCOUNT_DAILY + SP_LOAD_STORAGE_TRUTH + daily task (table/stage/failsafe/hybrid/archive cool+cold from STORAGE_USAGE); per-DB storage readers moved to monthly-average billing basis (F1); tier-rate SETTINGS seeded (R3/F1b)' AS DESCRIPTION
WHERE NOT EXISTS (SELECT 1 FROM DBA_MAINT_DB.OVERWATCH.SCHEMA_VERSION WHERE VERSION = 46);

-- ===========================================================================
-- >>> V047__pattern_cost_qas.sql
-- ===========================================================================
-- V047: Query Acceleration in the pattern-cost mart (Codex 2026-07-14, audit item 4).
-- SP_LOAD_PATTERN_COST summed only CREDITS_ATTRIBUTED_COMPUTE; accelerated
-- queries also bill CREDITS_USED_QUERY_ACCELERATION. Re-derived from V036 with
-- that single addition so MART_PATTERN_COST_DAILY.CREDITS_ATTRIBUTED reflects
-- total measured compute. No schema/table/task change. Apply AFTER V046.
-- Idempotent; safe to re-run.

EXECUTE IMMEDIATE
$$
DECLARE
    v NUMBER;
    not_ready EXCEPTION (-20047, 'V047 requires V046 first - apply migrations in order.');
BEGIN
    SELECT MAX(VERSION) INTO :v FROM DBA_MAINT_DB.OVERWATCH.SCHEMA_VERSION;
    IF (v < 46) THEN
        RAISE not_ready;
    END IF;
END;
$$;

CREATE OR REPLACE PROCEDURE DBA_MAINT_DB.OVERWATCH.SP_LOAD_PATTERN_COST(DAYS_BACK FLOAT)
RETURNS VARCHAR
LANGUAGE SQL
EXECUTE AS OWNER
AS
$$
BEGIN
    MERGE INTO DBA_MAINT_DB.OVERWATCH.MART_PATTERN_COST_DAILY t
    USING (
        SELECT m.DAY, m.QUERY_HASH, m.COMPANY,
               SUM(m.RUNS) AS RUNS,
               SUM(m.CREDITS_ATTRIBUTED) AS CREDITS_ATTRIBUTED,
               SUM(m.USERS) AS USERS
        FROM (
            SELECT g.DAY, g.QUERY_HASH,
                   DBA_MAINT_DB.OVERWATCH.COMPANY_FOR_WAREHOUSE(g.WAREHOUSE_NAME) AS COMPANY,
                   g.RUNS, g.CREDITS_ATTRIBUTED, g.USERS
            FROM (
                SELECT CAST(q.START_TIME AS DATE) AS DAY,
                       q.QUERY_PARAMETERIZED_HASH AS QUERY_HASH,
                       COALESCE(q.WAREHOUSE_NAME, 'NONE') AS WAREHOUSE_NAME,
                       COUNT(*) AS RUNS,
                       SUM(a.CREDITS_ATTRIBUTED_COMPUTE + COALESCE(a.CREDITS_USED_QUERY_ACCELERATION, 0)) AS CREDITS_ATTRIBUTED,
                       COUNT(DISTINCT q.USER_NAME) AS USERS
                FROM SNOWFLAKE.ACCOUNT_USAGE.QUERY_ATTRIBUTION_HISTORY a
                JOIN SNOWFLAKE.ACCOUNT_USAGE.QUERY_HISTORY q
                  ON q.QUERY_ID = a.QUERY_ID
                 AND q.START_TIME >= DATEADD('day', -1 * :DAYS_BACK, CURRENT_DATE())
                WHERE a.START_TIME >= DATEADD('day', -1 * :DAYS_BACK, CURRENT_DATE())
                  AND q.QUERY_PARAMETERIZED_HASH IS NOT NULL
                GROUP BY 1, 2, 3
            ) g
        ) m
        GROUP BY 1, 2, 3
    ) s
    ON t.DAY = s.DAY AND t.QUERY_HASH = s.QUERY_HASH AND t.COMPANY = s.COMPANY
    WHEN MATCHED THEN UPDATE SET
        t.RUNS = s.RUNS, t.CREDITS_ATTRIBUTED = s.CREDITS_ATTRIBUTED,
        t.USERS = s.USERS, t.LOAD_TS = CURRENT_TIMESTAMP()
    WHEN NOT MATCHED THEN INSERT (DAY, QUERY_HASH, COMPANY, RUNS, CREDITS_ATTRIBUTED, USERS)
    VALUES (s.DAY, s.QUERY_HASH, s.COMPANY, s.RUNS, s.CREDITS_ATTRIBUTED, s.USERS);
    RETURN 'OK';
END;
$$;

CALL DBA_MAINT_DB.OVERWATCH.SP_LOAD_PATTERN_COST(90);

INSERT INTO DBA_MAINT_DB.OVERWATCH.SCHEMA_VERSION (VERSION, DESCRIPTION)
SELECT 47 AS VERSION,
       'pattern-cost mart includes Query Acceleration: SP_LOAD_PATTERN_COST re-derived from V036 + CREDITS_USED_QUERY_ACCELERATION (Codex audit item 4)' AS DESCRIPTION
WHERE NOT EXISTS (SELECT 1 FROM DBA_MAINT_DB.OVERWATCH.SCHEMA_VERSION WHERE VERSION = 47);

-- ===========================================================================
-- >>> V048__object_cost_ledger.sql
-- ===========================================================================
-- V048: FACT_OBJECT_COST_DAILY — the additive object-cost ledger (Codex
-- architectural item 10 / Phase 2, 2026-07-14). One row per day / object /
-- cost-arm / company, credits additive across arms:
--   QUERY_COMPUTE           measured compute+QAS from QUERY_ATTRIBUTION_HISTORY,
--                           split EQUALLY across the base objects each query
--                           touched (ACCESS_HISTORY) so totals stay additive
--   QUERY_COMPUTE_RESIDUAL  measured credits for queries with no base object
--   CLUSTERING / MV_REFRESH / SERVERLESS_TASK / SNOWPIPE / SEARCH_OPT
--                           direct per-object serverless credits
-- Verified accessible on this account 2026-07-14 (ACCESS_HISTORY present, so
-- the object split is possible; MV/Search-Opt empty today but wired for later).
-- Apply AFTER V047. Idempotent; safe to re-run.

EXECUTE IMMEDIATE
$$
DECLARE
    v NUMBER;
    not_ready EXCEPTION (-20048, 'V048 requires V047 first - apply migrations in order.');
BEGIN
    SELECT MAX(VERSION) INTO :v FROM DBA_MAINT_DB.OVERWATCH.SCHEMA_VERSION;
    IF (v < 47) THEN
        RAISE not_ready;
    END IF;
END;
$$;

CREATE TRANSIENT TABLE IF NOT EXISTS DBA_MAINT_DB.OVERWATCH.FACT_OBJECT_COST_DAILY (
    DAY           DATE          NOT NULL,
    OBJECT_FQN    VARCHAR(600)  NOT NULL,
    OBJECT_DOMAIN VARCHAR(40),
    COST_ARM      VARCHAR(30)   NOT NULL,
    COMPANY       VARCHAR(40),
    CREDITS       NUMBER(24,6),
    LOAD_TS       TIMESTAMP_NTZ NOT NULL DEFAULT CURRENT_TIMESTAMP()
);

CREATE OR REPLACE PROCEDURE DBA_MAINT_DB.OVERWATCH.SP_LOAD_OBJECT_COST(DAYS_BACK FLOAT)
RETURNS VARCHAR
LANGUAGE SQL
EXECUTE AS OWNER
AS
$$
DECLARE
    lo DATE;
BEGIN
    lo := DATEADD('day', -GREATEST(COALESCE(:DAYS_BACK, 3), 1)::INT, CURRENT_DATE());
    DELETE FROM DBA_MAINT_DB.OVERWATCH.FACT_OBJECT_COST_DAILY WHERE DAY >= :lo;

    -- Direct per-object serverless arms -----------------------------------
    INSERT INTO DBA_MAINT_DB.OVERWATCH.FACT_OBJECT_COST_DAILY (DAY, OBJECT_FQN, OBJECT_DOMAIN, COST_ARM, COMPANY, CREDITS)
    SELECT START_TIME::DATE, DATABASE_NAME || '.' || SCHEMA_NAME || '.' || TABLE_NAME,
           'TABLE', 'CLUSTERING',
           DBA_MAINT_DB.OVERWATCH.COMPANY_FOR_DATABASE(DATABASE_NAME), SUM(COALESCE(CREDITS_USED, 0))
    FROM SNOWFLAKE.ACCOUNT_USAGE.AUTOMATIC_CLUSTERING_HISTORY
    WHERE START_TIME >= :lo AND CREDITS_USED > 0
    GROUP BY 1, 2, 3, 4, 5;

    INSERT INTO DBA_MAINT_DB.OVERWATCH.FACT_OBJECT_COST_DAILY (DAY, OBJECT_FQN, OBJECT_DOMAIN, COST_ARM, COMPANY, CREDITS)
    SELECT START_TIME::DATE, DATABASE_NAME || '.' || SCHEMA_NAME || '.' || TABLE_NAME,
           'MATERIALIZED_VIEW', 'MV_REFRESH',
           DBA_MAINT_DB.OVERWATCH.COMPANY_FOR_DATABASE(DATABASE_NAME), SUM(COALESCE(CREDITS_USED, 0))
    FROM SNOWFLAKE.ACCOUNT_USAGE.MATERIALIZED_VIEW_REFRESH_HISTORY
    WHERE START_TIME >= :lo AND CREDITS_USED > 0
    GROUP BY 1, 2, 3, 4, 5;

    INSERT INTO DBA_MAINT_DB.OVERWATCH.FACT_OBJECT_COST_DAILY (DAY, OBJECT_FQN, OBJECT_DOMAIN, COST_ARM, COMPANY, CREDITS)
    SELECT START_TIME::DATE, DATABASE_NAME || '.' || SCHEMA_NAME || '.' || TABLE_NAME,
           'TABLE', 'SEARCH_OPT',
           DBA_MAINT_DB.OVERWATCH.COMPANY_FOR_DATABASE(DATABASE_NAME), SUM(COALESCE(CREDITS_USED, 0))
    FROM SNOWFLAKE.ACCOUNT_USAGE.SEARCH_OPTIMIZATION_HISTORY
    WHERE START_TIME >= :lo AND CREDITS_USED > 0
    GROUP BY 1, 2, 3, 4, 5;

    INSERT INTO DBA_MAINT_DB.OVERWATCH.FACT_OBJECT_COST_DAILY (DAY, OBJECT_FQN, OBJECT_DOMAIN, COST_ARM, COMPANY, CREDITS)
    SELECT START_TIME::DATE, DATABASE_NAME || '.' || SCHEMA_NAME || '.' || TASK_NAME,
           'TASK', 'SERVERLESS_TASK',
           DBA_MAINT_DB.OVERWATCH.COMPANY_FOR_DATABASE(DATABASE_NAME), SUM(COALESCE(CREDITS_USED, 0))
    FROM SNOWFLAKE.ACCOUNT_USAGE.SERVERLESS_TASK_HISTORY
    WHERE START_TIME >= :lo AND CREDITS_USED > 0
    GROUP BY 1, 2, 3, 4, 5;

    INSERT INTO DBA_MAINT_DB.OVERWATCH.FACT_OBJECT_COST_DAILY (DAY, OBJECT_FQN, OBJECT_DOMAIN, COST_ARM, COMPANY, CREDITS)
    SELECT START_TIME::DATE, PIPE_NAME, 'PIPE', 'SNOWPIPE',
           DBA_MAINT_DB.OVERWATCH.COMPANY_FOR_DATABASE(SPLIT_PART(PIPE_NAME, '.', 1)), SUM(COALESCE(CREDITS_USED, 0))
    FROM SNOWFLAKE.ACCOUNT_USAGE.PIPE_USAGE_HISTORY
    WHERE START_TIME >= :lo AND CREDITS_USED > 0
    GROUP BY 1, 2, 3, 4, 5;

    -- Measured query compute, split EQUALLY across accessed base objects ---
    INSERT INTO DBA_MAINT_DB.OVERWATCH.FACT_OBJECT_COST_DAILY (DAY, OBJECT_FQN, OBJECT_DOMAIN, COST_ARM, COMPANY, CREDITS)
    WITH qa AS (
        SELECT QUERY_ID, MIN(START_TIME)::DATE AS DAY,
               SUM(COALESCE(CREDITS_ATTRIBUTED_COMPUTE, 0) + COALESCE(CREDITS_USED_QUERY_ACCELERATION, 0)) AS CREDITS
        FROM SNOWFLAKE.ACCOUNT_USAGE.QUERY_ATTRIBUTION_HISTORY
        WHERE START_TIME >= :lo
        GROUP BY QUERY_ID
        HAVING SUM(COALESCE(CREDITS_ATTRIBUTED_COMPUTE, 0) + COALESCE(CREDITS_USED_QUERY_ACCELERATION, 0)) > 0
    ),
    dedup AS (
        SELECT DISTINCT ah.QUERY_ID,
               f.value:"objectName"::STRING AS OBJECT_FQN,
               f.value:"objectDomain"::STRING AS OBJECT_DOMAIN
        FROM SNOWFLAKE.ACCOUNT_USAGE.ACCESS_HISTORY ah,
             LATERAL FLATTEN(input => ah.BASE_OBJECTS_ACCESSED) f
        WHERE ah.QUERY_START_TIME >= :lo
          AND f.value:"objectName" IS NOT NULL
          AND f.value:"objectDomain"::STRING IN ('Table', 'Materialized view')
    ),
    counts AS (SELECT QUERY_ID, COUNT(*) AS N FROM dedup GROUP BY QUERY_ID)
    SELECT qa.DAY, d.OBJECT_FQN, UPPER(REPLACE(d.OBJECT_DOMAIN, ' ', '_')), 'QUERY_COMPUTE',
           DBA_MAINT_DB.OVERWATCH.COMPANY_FOR_DATABASE(SPLIT_PART(d.OBJECT_FQN, '.', 1)),
           SUM(qa.CREDITS / c.N)
    FROM qa
    JOIN dedup d ON d.QUERY_ID = qa.QUERY_ID
    JOIN counts c ON c.QUERY_ID = qa.QUERY_ID
    GROUP BY 1, 2, 3, 4, 5;

    -- Residual: measured credits for queries that touched no base object ---
    INSERT INTO DBA_MAINT_DB.OVERWATCH.FACT_OBJECT_COST_DAILY (DAY, OBJECT_FQN, OBJECT_DOMAIN, COST_ARM, COMPANY, CREDITS)
    WITH qa AS (
        SELECT QUERY_ID, MIN(START_TIME)::DATE AS DAY,
               SUM(COALESCE(CREDITS_ATTRIBUTED_COMPUTE, 0) + COALESCE(CREDITS_USED_QUERY_ACCELERATION, 0)) AS CREDITS
        FROM SNOWFLAKE.ACCOUNT_USAGE.QUERY_ATTRIBUTION_HISTORY
        WHERE START_TIME >= :lo
        GROUP BY QUERY_ID
        HAVING SUM(COALESCE(CREDITS_ATTRIBUTED_COMPUTE, 0) + COALESCE(CREDITS_USED_QUERY_ACCELERATION, 0)) > 0
    ),
    obj_q AS (
        SELECT DISTINCT ah.QUERY_ID
        FROM SNOWFLAKE.ACCOUNT_USAGE.ACCESS_HISTORY ah,
             LATERAL FLATTEN(input => ah.BASE_OBJECTS_ACCESSED) f
        WHERE ah.QUERY_START_TIME >= :lo
          AND f.value:"objectDomain"::STRING IN ('Table', 'Materialized view')
    )
    SELECT qa.DAY, 'UNATTRIBUTED', 'RESIDUAL', 'QUERY_COMPUTE_RESIDUAL', NULL, SUM(qa.CREDITS)
    FROM qa
    LEFT JOIN obj_q ON obj_q.QUERY_ID = qa.QUERY_ID
    WHERE obj_q.QUERY_ID IS NULL
    GROUP BY 1;

    MERGE INTO DBA_MAINT_DB.OVERWATCH.SOURCE_FRESHNESS_STATE t
    USING (
        SELECT 'FACT_OBJECT_COST_DAILY' AS SOURCE_NAME, MAX(LOAD_TS) AS LAST_LOAD_TS, COUNT(*) AS ROW_COUNT
        FROM DBA_MAINT_DB.OVERWATCH.FACT_OBJECT_COST_DAILY
    ) s
    ON t.SOURCE_NAME = s.SOURCE_NAME
    WHEN MATCHED THEN UPDATE SET t.LAST_LOAD_TS = s.LAST_LOAD_TS, t.ROW_COUNT = s.ROW_COUNT, t.SNAPSHOT_TS = CURRENT_TIMESTAMP()
    WHEN NOT MATCHED THEN INSERT (SOURCE_NAME, LAST_LOAD_TS, ROW_COUNT) VALUES (s.SOURCE_NAME, s.LAST_LOAD_TS, s.ROW_COUNT);

    RETURN 'OK';
END;
$$;

-- First fill: 14 days (ACCESS_HISTORY x QUERY_ATTRIBUTION is heavy; the daily task keeps 3d fresh).
CALL DBA_MAINT_DB.OVERWATCH.SP_LOAD_OBJECT_COST(14);

CREATE TASK IF NOT EXISTS DBA_MAINT_DB.OVERWATCH.TASK_LOAD_OBJECT_COST
    WAREHOUSE = WH_ALFA_OVERWATCH
    SCHEDULE = 'USING CRON 45 6 * * * America/Chicago'
AS
    CALL DBA_MAINT_DB.OVERWATCH.SP_LOAD_OBJECT_COST(3);

ALTER TASK IF EXISTS DBA_MAINT_DB.OVERWATCH.TASK_LOAD_OBJECT_COST RESUME;

INSERT INTO DBA_MAINT_DB.OVERWATCH.SCHEMA_VERSION (VERSION, DESCRIPTION)
SELECT 48 AS VERSION,
       'FACT_OBJECT_COST_DAILY additive object-cost ledger: measured query compute+QAS split across accessed base objects (ACCESS_HISTORY) + residual, plus direct clustering/MV/serverless-task/snowpipe/search-opt arms; daily task (Codex architectural Phase 2)' AS DESCRIPTION
WHERE NOT EXISTS (SELECT 1 FROM DBA_MAINT_DB.OVERWATCH.SCHEMA_VERSION WHERE VERSION = 48);
